INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q46x9-0000-4000-a000-000000000511',
  'a000046-0000-4000-a000-000000000501',
  'La v&iacute;a gluconeog&eacute;nica, se ejecuta en sentido opuesto a la v&iacute;a glucol&iacute;tica &iquest;c&oacute;mo soluci&oacute;n al h&iacute;gado las tres etapas irreversibles de la gluc&oacute;lisis?',
  9,
  '[{"id":"5290","text":"El h&iacute;gado utilizar cuatro enzimas &uacute;nicas: la piruvato carboxilasa (PC) en la mitocondria, la fosfoenolpiruvato carboxiquinasa (PEPCK) me citoplasma para evitar la piruvato quinasa (PK), la fructosa 1,6-bisfosfatasa (Fru-1,6-BPasa) para no utilizar la fosfofructoquinasa I (PFK-I) y la glucosa 6 fosfatasa para evitar la glucoquinasa (GK)."},{"id":"5288","text":"El h&iacute;gado no tiene que solventar ninguna etapa irreversible en la gluc&oacute;lisis, puesto que utiliza las mismas enzimas glucol&iacute;ticas pero en sentido inverso para que la gluconeog&eacute;nesis."},{"id":"5289","text":"La &uacute;nica reacci&oacute;n irreversible de la gluc&oacute;lisis es solventada por el h&iacute;gado cola conversi&oacute;n de glucosa 6 fosfato o a glucosa 1 fosfato y catalizada por la enzima &uacute;nica glucosa 6 fosfatasa en la gluconeog&eacute;nesis."},{"id":"5291","text":"Para solventar estas tres reacciones irreversibles, el h&iacute;gado utilizada s&oacute;lo dos enzimas &uacute;nicas: la piruvato carboxilasa (PC) en la mitocondria y la fosfoenolpiruvato carboxiquinasa (PEPCK) me citoplasma."},{"id":"5292","text":"Ninguna de las respuestas anteriores es correcta"}]',
  '5290',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q46x10-0000-4000-a000-000000000512',
