INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x20-0000-4000-a000-000000000823',
  'a000058-0000-4000-a000-000000000800',
  'Se&ntilde;ala la respuesta correcta en relaci&oacute;n a la actividad de los RTKs (receptores tirosin kinasa)',
  20,
  '[{"id":"7774","text":"Los RTKs son una clase de receptores con actividad enzim&aacute;tica, estimulan su actividad mediante la dimerizaci&oacute;n de sus dominios y se fosforilan de forma cruzada sobre varias tirosinas (transautofosforilaci&oacute;n), lo que incrementar a&uacute;n m&aacute;s su actividad"},{"id":"7773","text":"Los RTKs son receptores acoplados a prote&iacute;nas G, estimulan su activaci&oacute;n mediante la uni&oacute;n a su dominio intracelular al complejo heterotrim&eacute;rico de la prote&iacute;na G, lo que fosforilada de forma cruzada en varias tirosinas (transautofosforilaci&oacute;n) e incrementar a&uacute;n m&aacute;s su actividad"},{"id":"7775","text":"Los RTKs son a clase de receptores con actividad enzim&aacute;tica, estimulan su activaci&oacute;n mediante la dimerizaci&oacute;n de sus dominios y se fosforilan de forma cruzada sobre varias tirosinas (transautofosforilaci&oacute;n), para auto inhibir su se&ntilde;alizaci&oacute;n"},{"id":"7776","text":"Los RTKs son una clase de receptores acoplados a canales y i&oacute;nicos, estimulan su activaci&oacute;n mediante el transporte i&oacute;nico de calcio y sodio y se fosforilan de forma cruzada sobre tirosinas, lo que inhibe su actividad"},{"id":"7777","text":"Los RTKs son una clase de receptores con actividad enzim&aacute;tica, estimulan su activaci&oacute;n mediante la uni&oacute;n del ligando se espec&iacute;ficos a la regi&oacute;n extracelular, que lleva a cabo la transautofosforilaci&oacute;n en residuos de serina"}]',
  '7774',
  '2026-04-17 15:42:45'
);
