INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x33-0000-4000-a000-000000000836',
  'a000058-0000-4000-a000-000000000800',
  'El s&iacute;ndrome de inmunodeficiencia combinada grave (SICG):',
  33,
  '[{"id":"7841","text":"El 50% de los pacientes que presentan la variante de herencia recesiva autos&oacute;mica presentan una deficiencia gen&eacute;tica de adenosina desaminaci&oacute;n, una enzima de la v&iacute;a de recuperaci&oacute;n de las purinas"},{"id":"7837","text":"El 50% de los pacientes que presentan la variante de herencia recesiva autos&oacute;mica presentan una deficiencia gen&eacute;tica en xantina oxidasa, una enzima de la v&iacute;a de recuperaci&oacute;n de las pirimidinas"},{"id":"7838","text":"Dentro del cuadro cl&iacute;nico los pacientes manifiestan infecciones que no llegan hacer muy graves"},{"id":"7839","text":"Presentan una deficiencia en adenosina desaminasa, una enzima de la v&iacute;a de s&iacute;ntesis de Novo de las purinas y debido a la exposici&oacute;n ambiental a t&oacute;xicos, que no causa efectos muy severos"},{"id":"7840","text":"Es un s&iacute;ndrome muy frecuente y no llega a ser mortal y tiene que ver con las diversas causas ambientales que afectan exclusivamente a la funcionalidad de las c&eacute;lulas NK"}]',
  '7841',
  '2026-04-17 15:42:45'
);
