INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x35-0000-4000-a000-000000000838',
  'a000058-0000-4000-a000-000000000800',
  'En los individuos hipercolesterol&eacute;micos:',
  35,
  '[{"id":"7850","text":"Con una mutaci&oacute;n con ganancia de funci&oacute;n, la cerina proteasa PCSK9 tiene una mayor afinidad por el receptor de LDL, el cual es internalizado con mayor facilidad para su posterior degradaci&oacute;n, por lo que en estos individuos disminuye la presencia de receptor LDL en la membrana plasm&aacute;tica de las c&eacute;lulas, reduciendo la capacidad de captaci&oacute;n del colesterol al citoplasma celular, lo que incrementa los niveles de colesterol en plasma."},{"id":"7847","text":"Los f&aacute;rmacos hipercolesterolemiantes son anticuerpos monoclonales dirigidos a inducir la actividad de PCSK9"},{"id":"7848","text":"Los f&aacute;rmacos hipercolesterolemiantes son anticuerpos monoclonales dirigidos a inhibir la actividad de PCSK9"},{"id":"7849","text":"Con una mutaci&oacute;n con p&eacute;rdida de funci&oacute;n, la serina proteasa PCSK9 tiene una menor afinidad por el receptor de LDL el cual es internalizado con menor facilidad para su posterior degradaci&oacute;n, por lo que en estos individuos aumenta la presencia del receptor LDL en la membrana plasm&aacute;tica de las c&eacute;lulas, incrementando la capacidad de captaci&oacute;n de colesterol al citoplasma celular, lo que disminuye los niveles de colesterol en plasma."},{"id":"7851","text":"No existe un tratamiento dirigido que regule la actividad de PCSK9"}]',
  '7850',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x36-0000-4000-a000-000000000839',
  'a000058-0000-4000-a000-000000000800',
  'La Uni&oacute;n de la insulina a su receptor:',
  36,
  '[{"id":"7855","text":"Inhibe la gluconeog&eacute;nesis por activaci&oacute;n de una cascada de se&ntilde;alizaci&oacute;n intracelular mediada por la prote&iacute;na quinasa B (PKB) la cual fosforila el factor de transcripci&oacute;n FOXO1 en el citosol el cual es marcado por la uni&oacute;n de mol&eacute;culas ubiquitina para su degradaci&oacute;n v&iacute;a proteasoma. Esta acci&oacute;n impide que FOXO1 se internalice en el n&uacute;cleo e inhiba De respuesta a transcripci&oacute;n g&eacute;nica de las enzimas fosfoenolpiruvato carboxiquinasa (PEP carboxiquinasa) y glucosa 6 fosfatasa (Glu-6-Pasa)."},{"id":"7852","text":"inhibe la gluconeog&eacute;nesis por activaci&oacute;n de una cascada de se&ntilde;alizaci&oacute;n intracelular mediada por la prote&iacute;na quinasa B (PKB), la cual fosforila al factor de transcripci&oacute;n GSK3 en el citosol el cual es marcado por la uni&oacute;n de mol&eacute;culas de ubiquitina para su degradaci&oacute;n v&iacute;a proteasoma. Esta acci&oacute;n impide que GSK3 internalicen el n&uacute;cleo e inhiba la transcripci&oacute;n g&eacute;nica de fosfoenolpiruvato carboxiquinasa (PEP carboxiquinasa) y glucosa 6 fosfatasa (Glu-6-Pasa)"},{"id":"7853","text":"activa una cascada de se&ntilde;alizaci&oacute;n intracelular mediada por la protein quinasa B (PKB), La cual fosforila el factor de transcripci&oacute;n FOXO1 en el citosol el cual es marcado por la uni&oacute;n de mol&eacute;culas ubiquitina para su degradaci&oacute;n v&iacute;a proteasoma. Esta acci&oacute;n impide que FOXO1 internalicen el n&uacute;cleo y se una a elementos de respuesta que inhiben la transcripci&oacute;n g&eacute;nica de prote&iacute;nas relacionadas con la glucog&eacute;nesis: gluc&oacute;geno sintasa y gluc&oacute;geno fosforilasa."},{"id":"7854","text":"Induce una cascada de se&ntilde;alizaci&oacute;n intracelular mediada la por la prote&iacute;na quinasa B (PKB) la cual fosforila al factor de transcripci&oacute;n GSK3 en el citosol el cual es marcado por la uni&oacute;n de mol&eacute;culas ubiquitina para su degradaci&oacute;n v&iacute;a proteosoma. Esta acci&oacute;n impide qu&eacute; GSK3 se internalice en el n&uacute;cleo y se una a elementos de respuesta que inducen la transcripci&oacute;n g&eacute;nica de prote&iacute;nas relacionadas con la glucolisis: el complejo piruvato quinasa."},{"id":"7856","text":"Activa la gluconeog&eacute;nesis mediante la acci&oacute;n de una cascada de se&ntilde;alizaci&oacute;n intracelular mediada por la prote&iacute;na quinasa B (PKB) la cual fosforila el factor de transcripci&oacute;n FOXO1 en el citosol el cual es marcado por la Uni&oacute;n de mol&eacute;culas ubiquitina para su degradaci&oacute;n v&iacute;a proteosoma. Esta acci&oacute;n favorece la entrada de FOXO1 en el n&uacute;cleo y se una a elementos de respuesta que inducen la transcripci&oacute;n g&eacute;nica de prote&iacute;nas relacionadas."}]',
  '7855',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
