);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x38-0000-4000-a000-000000000841',
  'a000058-0000-4000-a000-000000000800',
  'Las prote&iacute;nas Ras:',
  38,
  '[{"id":"7864","text":"Son GTPasa monom&eacute;ricas que transmiten se&ntilde;ales intracelulares desde receptores de superficie, son activadas por los factores intercambiadores de nucle&oacute;tidos de guanina (GEF) ya que estimula a la prote&iacute;na Ras a liberar el GDP unido para ser intercambiado por GTP. Su actividad promueve procesos de proliferaci&oacute;n o diferenciaci&oacute;n celular."},{"id":"7862","text":"son metilasas que transmiten se&ntilde;ales intracelulares desde receptores de superficie, Son activadas por serinas prote&iacute;na quinasa ya que estimulan la liberaci&oacute;n del GDP unido y se ha intercambiado por GTP. Su actividad promueve procesos de supervivencia celular."},{"id":"7863","text":"Son GTPasas monom&eacute;ricas que transmiten se&ntilde;ales desde receptores intracelulares, son activadas por prote&iacute;nas activa antes GAP ya que estimula la hidr&oacute;lisis de GTP unido. Su actividad promueve procesos de autofagia celular."},{"id":"7865","text":"son receptores de superficie tirosina kinasa que transmiten se&ntilde;ales intracelulares tras ser activados por los factores intercambiadores de nucle&oacute;tidos de guanina (GEF) ya que estimulan la liberaci&oacute;n de grupos fosfato unidos a su prote&iacute;na armaz&oacute;n. Su actividad promueve procesos de proliferaci&oacute;n y supervivencia celular."},{"id":"7866","text":"Son ATPasa monom&eacute;ricas que transmiten se&ntilde;ales extracelulares desde receptores de superficie, son activadas por el factor intercambiador de nucle&oacute;tidos de guanina (GEF) ya que estimula a la prote&iacute;na a que libere el GDP unido y se ha intercambiado por GTP. su actividad promueve procesos de apoptosis o muerte celular programada."}]',
  '7864',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x39-0000-4000-a000-000000000842',
  'a000058-0000-4000-a000-000000000800',
  'La adrenalina y el glucag&oacute;n:',
  39,
  '[{"id":"7871","text":"Se une a receptores adren&eacute;rgicos de tipo GPCR estimulando la degradaci&oacute;n de gluc&oacute;geno en m&uacute;sculo esquel&eacute;tico e h&iacute;gado, respectivamente, empleando respuestas celulares mediadas por la enzima adenilato ciclasa y el AMPc."},{"id":"7867","text":"Se unen a receptores glutamat&eacute;gicos de tipo tirosina quinasa (RTK) estimulando la s&iacute;ntesis de gluc&oacute;geno en m&uacute;sculo esquel&eacute;tico e h&iacute;gado, respectivamente, empleando respuestas celulares mediadas por la enzima adenilato ciclasa y el AMPc."},{"id":"7868","text":"Se unen a receptores adren&eacute;rgicos de tipo GPCR estimulando la degradaci&oacute;n de gluc&oacute;geno en m&uacute;sculo esquel&eacute;tico e h&iacute;gado, respectivamente, empleando respuestas celulares mediadas por la activaci&oacute;n de la fosfolipasa C (PLC)."},{"id":"7869","text":"se unen a receptores adren&eacute;rgicos de tipo RTK estimulando la s&iacute;ntesis de l&iacute;pidos en m&uacute;sculo esquel&eacute;tico e h&iacute;gado, respectivamente, empleando respuestas celulares mediadas por la acci&oacute;n de la fosfolipasa C (PLC)"},{"id":"7870","text":"Se unen a receptores dependientes de canales i&oacute;nicos de sodio estimulando la degradaci&oacute;n de gluc&oacute;geno en m&uacute;sculos esquel&eacute;tico e h&iacute;gado, respectivamente, empleando respuestas celulares mediadas por la enzima adenilato ciclasa y el AMPc."}]',
  '7871',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x40-0000-4000-a000-000000000843',
  'a000058-0000-4000-a000-000000000800',
  'Indique la respuesta incorrecta respecto a las alteraciones morfol&oacute;gicas en apoptosis:',
  40,
  '[{"id":"7876","text":"p&eacute;rdida de integridad de la membrana"},{"id":"7872","text":"La envoltura nuclear se desensambla"},{"id":"7873","text":"la superficie celular a menudo emite protusiones y si la c&eacute;lula es grande a menudo se rompe en fragmentos denominados cuerpos apopt&oacute;ticos"},{"id":"7874","text":"el citoesqueleto se colapsa"},{"id":"7875","text":"la cromatina nuclear se condensa y se fragmenta"}]',
  '7876',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x41-0000-4000-a000-000000000844',
  'a000058-0000-4000-a000-000000000800',
  'Indique la respuesta correcta respecto a las caracter&iacute;sticas de las c&eacute;lulas senescentes:',
  41,
  '[{"id":"7881","text":"la senescencia tiene un papel dual en la oncog&eacute;nesis. En individuos j&oacute;venes, la c&eacute;lulas senescentes act&uacute;an como un mecanismo de seguridad que previene su transformaci&oacute;n en c&eacute;lulas tumorales. En las personas mayores, sin embargo, la acumulaci&oacute;n de c&eacute;lulas tiene excelentes promueve la generaci&oacute;n de un ambiente tisular que favorece la tumorog&eacute;nesis y la aparici&oacute;n de enfermedades degenerativas."},{"id":"7877","text":"la senescencia no es un mecanismo de seguridad que previene la formaci&oacute;n de tumores, al contrario, la acumulaci&oacute;n de c&eacute;lulas senescentes promueve la generaci&oacute;n de un ambiente tisular que favorece la tumorog&eacute;nesis y la aparici&oacute;n de enfermedades degenerativas"},{"id":"7878","text":"Las escencia no tiene ning&uacute;n papel fisiol&oacute;gico en c&aacute;ncer, pero s&iacute; en envejecimiento donde se ha visto que pueden agotar los tejidos de las c&eacute;lulas madre o progenitoras, lo que lleva a comprometer la reparaci&oacute;n, la regeneraci&oacute;n y recambio normal de tejidos conduciendo a una disminuci&oacute;n funcional."},{"id":"7879","text":"la senescencia es exclusivamente un mecanismo que impide la formaci&oacute;n de tumores, tanto en individuos j&oacute;venes como en personas mayores las c&eacute;lulas senescentes act&uacute;an como un mecanismo de seguridad que previene su transformaci&oacute;n en c&eacute;lulas tumorales."},{"id":"7880","text":"la senescencia no tiene ning&uacute;n papel fisiol&oacute;gico en c&aacute;ncer, pero s&iacute; en reparaci&oacute;n tisular debido a que las c&eacute;lulas senescentes desarrollan un fenotipo secreto (SAP) que pueden afectar a las c&eacute;lulas vecinas de forma paracrina"}]',
  '7881',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x42-0000-4000-a000-000000000845',
  'a000058-0000-4000-a000-000000000800',
  'Se&ntilde;ala la respuesta correcta respecto a las prote&iacute;nas implicadas en autofagia:',
  42,
  '[{"id":"7885","text":"En condiciones nutricionales normales la quinasa mTOR est&aacute; activa y fosforila directamente una de las prote&iacute;nas esenciales para la autofagia (Atg13, Presente en el complejo de iniciaci&oacute;n ULK1) evitando la formaci&oacute;n de autofagosomas."},{"id":"7882","text":"En condiciones nutricionales normales la quinasa GSK3 est&aacute; activa y fosforila directamente una de las prote&iacute;nas esenciales para la autofagia (Atg13, Presente en el complejo de iniciaci&oacute;n ULK1) evitando la formaci&oacute;n de autofagosomas."},{"id":"7883","text":"En condiciones nutricionales normales la quinasa mTOR est&aacute; inactiva y desfosforila directamente una de las prote&iacute;nas esenciales para la autofagia (Atg13, Presente en el complejo de iniciaci&oacute;n ULK1) favoreciendo la formaci&oacute;n de autofagosomas."},{"id":"7884","text":"En condiciones nutricionales normales la quinasa GSK3 est&aacute; inactiva y desfosforilaci&oacute;n directamente una de las prote&iacute;nas esenciales para la autofagia (Atg13, Presente en el complejo de iniciaci&oacute;n ULK1) favoreciendo la formaci&oacute;n de autofagosomas."},{"id":"7886","text":"En condiciones nutricionales normales, la quinasaKC est&aacute; activa y fosforila directamente una de las prote&iacute;nas esenciales para la autofagia (Atg13, Presente en el complejo de iniciaci&oacute;n ULK1) evitando la formaci&oacute;n de autofagosomas."}]',
  '7885',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x43-0000-4000-a000-000000000846',
  'a000058-0000-4000-a000-000000000800',
  'Se&ntilde;ala la respuesta incorrecta respecto a la enfermedad Alzheimer',
  43,
  '[{"id":"7887","text":"AD es una enfermedad de progresi&oacute;n r&aacute;pida, los primeros cambios moleculares aparecen temprano y r&aacute;pidamente aparecen los primeros s&iacute;ntomas, por lo que se diagnostica a tiempo"},{"id":"7888","text":"los primeros cambios (acumulaci&oacute;n Tau y Beta-amieloide) Se describen a nivel de la corteza e hipocampo, zonas importantes en la consolidaci&oacute;n de la memoria"},{"id":"7889","text":"existen dos marcadores histopatol&oacute;gicos de la enfermedad: placas beta-amieloides o seniles y ovillos neurofibrilares formados principalmente por agregados de la prote&iacute;na Tau."},{"id":"7890","text":"M&aacute;s del 95% de los casos son espor&aacute;dicos, sin embargo existe un n&uacute;mero peque&ntilde;o de casos (2-5%) y los que la enfermedad se Liga a genes concretos con patr&oacute;n de herencia autos&oacute;mica dominante"},{"id":"7891","text":"actualmente solo hay dos medicamentos aprobados: inhibidores de la acetilcolinesterasa y la memantina qu&eacute; es el agonista del glutamato para los receptores NMDA."}]',
  '7887',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q58x44-0000-4000-a000-000000000847',
  'a000058-0000-4000-a000-000000000800',
  'Rendimiento energ&eacute;tico neto de ATP por la oxidaci&oacute;n de una mol&eacute;cula de fructosa en el h&iacute;gado.',
  44,
  '[{"id":"7894","text":"hiperuricemia con la presencia de cristales o tofos de urato s&oacute;dico en el l&iacute;quido sinovial aislado de las articulaciones, dispuestos en el interior de neutr&oacute;filos con forma de aguja y que muestran birrefringencia negativa a la luz polarizada tras observar los al microscopio. Concentraci&oacute;n elevada de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagociticas como monocitos y macr&oacute;fagos en el l&iacute;quido sinovial. Si se trata de un primer episodio o crisis aguda se le administra un tratamiento que consiste en prednisona (antiinflamatorio corticoideo) y colchicina (que altera los microt&uacute;bulos disminuyendo la inflamaci&oacute;n y fagocitosis). Se le recomienda cambios en la dieta (menos carne, alcohol, m&aacute;s ingesta de agua y dieta de adelgazamiento)"},{"id":"7892","text":"Un servicio m&eacute;dico recibe a un paciente aquejado de fuertes dolores en las articulaciones, enrojecimiento e inflamaci&oacute;n, y describe entre h&aacute;bitos de consumo mucha carne roja, alcohol y marisco. el servicio m&eacute;dico sospecha que se trata de un caso de gota por el exceso de &aacute;cido &uacute;rico pero tiene que confirmarlo con una serie de pruebas y ex&aacute;menes cl&iacute;nicos. Se&ntilde;ale la respuesta correcta que recoge las respuestas de los estudios realizados en el laboratorio y tratamiento o tratamientos a aplicar en el supuesto de confirmar el caso de gota en este paciente."},{"id":"7893","text":"Hiperuricemia con la presencia de cristales o tofos urato s&oacute;dico en el plasma sangu&iacute;neo, dispuestos en el interior de los neutr&oacute;filos con forma de aguja y que muestran y refringencia negativa a la luz polarizada tras observarlos al microscopio. concentraciones elevadas de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagoc&iacute;ticas como monocitos y macr&oacute;fagos en el plasma sangu&iacute;neo. Si el paciente ya es un hiperexcretor y sufre de nefropat&iacute;a, se le administra un tratamiento que consiste en prednisona (antiinflamatorio corticoideo) y colchicina (que altera los microt&uacute;bulos disminuyendo la inflamaci&oacute;n y fagocitosis). Se le recomienda cambios en la dieta (menos carne, alcohol, m&aacute;s ingesta de agua y dieta de adelgazamiento)"},{"id":"7895","text":"Hiperamonemia con la presencia de cristales o tofos de urato s&oacute;dico en el l&iacute;quido sinovial aislado de las articulaciones. Concentraciones disminuidas de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagoc&iacute;ticas como monocitos y macr&oacute;fagos en el l&iacute;quido sinovial. Si se trata de un episodio con gota refractaria se le administra tratamiento que consiste en un anticuerpo monoclonal dirigido contra las enzima xantina oxidasa que induzca una producci&oacute;n de ROS ayude a la ruptura de los cristales de &aacute;cido &uacute;rico en las articulaciones"},{"id":"7896","text":"Hipourocemia con la presencia de cristales o tofos de urato s&oacute;dico en el plasma sangu&iacute;neo, dispuestos en el interior de los neutr&oacute;filos con forma de aguja y que muestran birrefringencia positiva con la luz polarizada tras observarlos al microscopio. Concentraci&oacute;n baja de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagociticas como monocitos y macr&oacute;fagos en el l&iacute;quido sinovial. Si se trata di un primer episodio o crisis aguda si la administra un tratamiento que consiste en alopurinol, un activador de la enzima xantina oxidasa implicado en la bios&iacute;ntesis de &aacute;cido &uacute;rico."},{"id":"7897","text":"Hiperuricemia con la presencia de cristales o tofos diur&eacute;ticos s&oacute;dico en el l&iacute;quido sinovial aislados de las articulaciones, dispuestos el interior de los neutr&oacute;filos con forma de aguja y que muestran birrefringencia positiva a la luz polarizada tras observarlos al microscopio. Concentraciones elevadas de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagoc&iacute;ticas c&oacute;mo monocitos y macr&oacute;fagos en el l&iacute;quido sinovial. Si se trata de un primer episodio o crisis aguda se le administra un tratamiento est&aacute;ndar que consiste en lesinurad, un activador de la reabsorci&oacute;n de urato a nivel del transportador URAT1"},{"id":"7898","text":"Hiperamonemia con la presencia de cristales o tofos de urato s&oacute;dico en el l&iacute;quido sinovial aislados de las articulaciones, dispuestos en el interior de los neutr&oacute;filos con forma de aguja y que muestran birrefringencia negativa con la luz polarizada tras observarlos al microscopio. concentraciones elevadas de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagoc&iacute;ticas como monocitos y macr&oacute;fagos en el l&iacute;quido sinovial. Si se trata de un episodio con gota refractaria si le administra metotrexato que act&uacute;a como un quimioterap&eacute;utico inespec&iacute;fico pero que ayuda a la disoluci&oacute;n de los cristales de urato s&oacute;dico de las articulaciones y como antiinflamatorio."},{"id":"7899","text":"Hiperuricemia con la presencia de cristales o tofos de urato s&oacute;dico en el l&iacute;quido sinovial aislado de las articulaciones, dispuestos en el interior de los neutr&oacute;filos con forma de aguja y que muestran birrefringencia neutral a la luz polarizada al microscopio. concentraciones elevadas de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagociticas c&oacute;mo monocitos y macr&oacute;fagos en el l&iacute;quido sinovial. Si se trata de un primer episodio o crisis aguda se le administra un tratamiento que consiste en un activador (febuxostat) de la enzima xantina oxidasa, implicada en el metabolismo del &aacute;cido &uacute;rico"},{"id":"7900","text":"hiperuricemia con la presencia de cristales o tofos de urato s&oacute;dico en la orina, dispuestos en interior de los neutr&oacute;filos en forma de aguja y que muestran birrefringencia positiva con la luz polarizada tras observarlos al microscopio. Concentraciones elevadas de enzimas lisos&oacute;micas, citocinas y c&eacute;lulas fagoc&iacute;ticas como monocitos y macr&oacute;fagos en el l&iacute;quido sinovial. Si se trata de un primer episodio o crisis aguda se le administra un tratamiento que consiste en una uricasa recombinante a un pol&iacute;mero de polietilenglicol (PEG)(pegloticasa), que prolonga la semivida de la uricasa en plasma"}]',
  '7894',
  '2026-04-17 15:42:45'
);
