);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q174x0-0000-4000-a000-000000000853',
  'a000174-0000-4000-a000-000000000852',
  'Los receptores tirosina kinasa',
  0,
  '[{"id":"26248","text":"Cuando el ligando se une a sus dominios extracelulares, el efecto se activa y transfiere un grupo fosfato del ATP a determinadas cadenas laterales de tirosina, generando fosfotirosina que act&uacute;an como lugar de anclaje para prote&iacute;nas de se&ntilde;alizaci&oacute;n intracelular que hacer progresar la se&ntilde;al"},{"id":"26246","text":"Cuando el ligando se unen a sus dominios extracelulares, el receptor se activa y transfiere el ADP procedente del ATP a determinadas cadenas laterales de tirosina, generando ADP-tirosina que act&uacute;an como lugar de anclaje para prote&iacute;nas de se&ntilde;alizaci&oacute;n intracelular que hacen progresar la se&ntilde;al"},{"id":"26247","text":"Cuando el ligando se une a sus dominios extracelulares, el receptor se activa y transfiere un grupo CoA al acetil-CoA a determinadas cadenas laterales de tirosina, generando tirosina-CoA, que act&uacute;an como lugar de anclaje para prote&iacute;nas de se&ntilde;alizaci&oacute;n intracelular que hacen progresar la se&ntilde;al"},{"id":"26249","text":"Cuando el ligando se una a sus dominios extracelulares, el recepto se activa y transfiere AMP procedente del ATP a determinadas cadenas laterales de tirosinas, generando AMP-tirosina que act&uacute;an como lugar de anclaje para prote&iacute;nas de se&ntilde;alizaci&oacute;n intracelular que hacen progresar la se&ntilde;al"}]',
  '26248',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q175x0-0000-4000-a000-000000000855',
  'a000175-0000-4000-a000-000000000854',
  'En un GPCR activado:',
  0,
  '[{"id":"26243","text":"La unión de una señal extracelular al receptor modifica su conformaci6n, lo que modifica la conformación de la proteína G unida a él. La alteración de la subunidad alfa de la proteína G le permite intercambiar su GDP por GTP. Este intercambia desencadena un cambio conformacional que activa tanta a la subunidad alfa como al complejo beta-gamma, que ahora pueden interactuar con sus proteínas diana preferidas de la membrana plasmática por separado."},{"id":"26242","text":"La unión de una señal intracelular al receptor modifica su conformación, lo que modifica la conformación de la proteína G unida a él. La alteración de la subunidad alfa de la proteína G le permite intercambiar su GTP por GDP. El intercambio desencadena un cambio conformacional que activa tanto a la subunidad alfa como al complejo beta­ gamma por separado, que ahora pueden interactuar con sus proteínas diana preferidas de la membrana plasmática."},{"id":"26244","text":"La unión de una señal extracelular al receptor RTK modifica su conformación. La alteración de la subunidad alfa receptor RTK permite intercambiar su GDP por GTP. Este intercambio desencadena un cambio conformacional que activa tanto a la subunidad alfa como al complejo beta-gamma, que ahora pueden interactuar con sus proteínas diana preferidas de la membrana plasmática par separado."},{"id":"26245","text":"La unión de una señal extracelular al receptor modifica su conformaci6n, lo que modifica la conformaci6n de la proteína G unida a el. La alteraci6n de la subunidad beta de la proteína G le permite intercambiar su GDP por GTP. Este intercambio desencadena un cambio conformacional que activa tanto a la subunidad beta, así como a las subunidades alfa y gamma, que ahora pueden interactuar con sus proteínas diana preferidas de la membrana plasmática unidas en complejo."}]',
  '26243',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q176x0-0000-4000-a000-000000000857',
  'a000176-0000-4000-a000-000000000856',
  'Se ha descubierto en veneno en una serpiente de tropical que se une de forma irreversible a las deshidrogenasas: Glc-6P-deshidrogenasa y 6-fosfogluconato deshidrogenasa &iquest;qu&eacute; pasar&iacute;a si la serpiente inyectara el veneno en un humano? Indique cu&aacute;l de entre las siguientes respuestas es verdadera y la m&aacute;s completa.',
  0,
  '[{"id":"26238","text":"c, h y g son verdaderas"},{"id":"26227","text":"Podr&aacute; producir anemia hemol&iacute;tica, ya que el veneno interfiere en la glucolisis anaerobia al no poder convertirse el piruvato lactato"},{"id":"26228","text":"Nada, porque el paso que se ver&iacute;a afectado es la de la conversi&oacute;n del acetaldeh&iacute;do a etanol y esa reacci&oacute;n s&oacute;lo pasa en la glucolisis anaerobia en levaduras"},{"id":"26229","text":"La actividad antioxidante de glutati&oacute;n se ver&iacute;a limitada ya que no se regenerar&iacute;a el glutati&oacute;n reducido"},{"id":"26230","text":"La persona deb&iacute;a disminuida su producci&oacute;n de energ&iacute;a ya que el veneno inhibir&iacute;a el ciclo de los &aacute;cidos tricarbox&iacute;licos y con ello la fuente de producci&oacute;n de equivalentes de reducci&oacute;n que terminar&iacute;an convirti&eacute;ndose en ATP"},{"id":"26231","text":"La persona sufrir&aacute; una bajada energ&eacute;tica porque el veneno inhibe la beta-oxidaci&oacute;n mitocondrial y peroxisomal"},{"id":"26232","text":"El individuo no va a poder realizar s&iacute;ntesis de &aacute;cidos grasos ni desaturaci&oacute;n de los &aacute;cidos grasos que lo requieran"},{"id":"26233","text":"El individuo va a haber inhibida a su capacidad para sintetizar el colesterol"},{"id":"26234","text":"El individuo va a ver mermada su capacidad para sintetizar hormonas esteroideas"},{"id":"26235","text":"a y c son verdaderas"},{"id":"26236","text":"d y h son verdaderas"},{"id":"26237","text":"g y h son verdaderas"},{"id":"26239","text":"f, g y h son verdaderas"},{"id":"26240","text":"a, c y g son verdaderas"}]',
  '26238',
  '2026-04-17 15:42:45'
);
