VALUES (
  'q181x10-0000-4000-a000-000000000871',
  'a000181-0000-4000-a000-000000000860',
  'Los amino&aacute;cidos pueden perder el grupo amino en distintos tipos de reacci&oacute;n, indique cual es la correcta:',
  10,
  '[{"id":"26510","text":"Transaminaci&oacute;n: transferencia de un grupo amino a un ceto&aacute;cido. Eliminaci&oacute;n oxidativa de un grupo amino, reacci&oacute;n en la que interviene una flavina que se reduce. Desaminaci&oacute;n no oxidativa que solo ocurre en los hidroxi amino&aacute;cidos."},{"id":"26507","text":"Transaminaci&oacute;n que es la transferencia de un grupo amino al isobutiril CoA para entrar en el ciclo de la urea."},{"id":"26508","text":"Eliminaci&oacute;n no oxidativa del grupo amino que se da en los amino&aacute;cidos arom&aacute;ticos."},{"id":"26509","text":"Transaminaci&oacute;n oxidativa en la que interviene un NADP que se tiene que reducir."}]',
  '26510',
