INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q34x5-0000-4000-a000-000000002102',
  'a000034-0000-4000-a000-000000002094',
  '&iquest;Qu&eacute; ocurre si se altera la secuencia de amino&aacute;cidos de las se&ntilde;ales de localizaci&oacute;n nuclear de una prote&iacute;na de gran tama&ntilde;o?',
  5,
  '[{"id":"2521","text":"Las prote&iacute;nas pasan a trav&eacute;s del n&uacute;cleo gracias a receptores que se acoplan a la se&ntilde;al de localizaci&oacute;n, porque un cambio en la secuencia de esta impide este acoplamiento y por tanto el paso de prote&iacute;nas."},{"id":"2517","text":"Nada, aunque las macromol&eacute;culas como el ARN no pueden entrar o salir del n&uacute;cleo por s&iacute; mismas, las prote&iacute;nas son una excepci&oacute;n debido a su caracter&iacute;sticas especiales, como la carga."},{"id":"2518","text":"R&aacute;pidamente actuar&iacute;a el mecanismo de reparaci&oacute;n de la secuencia de amino&aacute;cidos, subsanando el error y permitiendo el paso a trav&eacute;s del n&uacute;cleo de las prote&iacute;nas"},{"id":"2519","text":"Al contrario que en otros sistemas de transporte de prote&iacute;nas de la c&eacute;lula, en el n&uacute;cleo las prote&iacute;nas atraviesan los complejos del poro nuclear plegadas. Un cambio en la secuencia de amino&aacute;cidos modificar&iacute;a su plegamiento y no podr&iacute;an atravesar los complejos del poro nuclear debido a su nueva forma."},{"id":"2520","text":"Las prote&iacute;nas atraviesan el n&uacute;cleo mediante cotransporte con la glucosa, por lo que un cambio en su secuencia, si bien puede hacerlas no funcionales, no altera su transporte a trav&eacute;s de la c&eacute;lula"}]',
  '2521',
  '2026-04-17 15:42:45'
);
