  'a000117-0000-4000-a000-000000003821',
  '&iquest;El filtrado glomerular contiene alb&uacute;mina?',
  5,
  '[{"id":"15153","text":"No, las albuminas no se filtran porque su tama&ntilde;o molecular es superior al de los poros glomerulares y adem&aacute;s su carga negativa dificulta el filtrado"},{"id":"15154","text":"Si, porque aunque su tama&ntilde;o molecular es algo superior al de los poros, la carga negativa facilita el filtrado."},{"id":"15155","text":"S&iacute;, pero solo en el primer tramo porque se filtran en el glom&eacute;rulo pero es reabsorbido en el t&uacute;bulo proximal junto con los amino&aacute;cidos."}]',
  '15153',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
