  'a000133-0000-4000-a000-000000003915',
  'Respecto del origen y funciones de la oxitocina identifica la respuesta correcta:',
  16,
  '[{"id":"17153","text":"Es una neuronahormona de s&iacute;ntesis hipotal&aacute;mica cuyos efectos est&aacute;n relacionados con la eyecci&oacute;n de la gl&aacute;ndula mamaria"},{"id":"17151","text":"Es una neurona hormona cuya s&iacute;ntesis en el hipot&aacute;lamo se activa por reflejo de Fergusson y est&aacute;n relacionados con la s&iacute;ntesis de leche en la gl&aacute;ndula mamaria"},{"id":"17152","text":"Es una hormona que por el reflejo de Ferguson se libera en la adenohip&oacute;fisis y su funci&oacute;n tienen que ver con las contracciones del miometrio en el parto"},{"id":"17154","text":"Es una hormona que se sintetiza y libera en la neurohip&oacute;fisis y sus funciones tienen que ver con la eyecci&oacute;n de leche por el est&iacute;mulo de reflejo de succi&oacute;n"}]',
  '17153',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
