INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q136x73-0000-4000-a000-000000004150',
  'a000136-0000-4000-a000-000000004076',
  'Identifica la respuesta correcta respecto a la fase de organificaci&oacute;n en la s&iacute;ntesis de hormona tiroidea:',
  73,
