INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q136x74-0000-4000-a000-000000004151',
  'a000136-0000-4000-a000-000000004076',
  '&iquest;La GnRH y la GHRH son neurohormonas?',
  74,
  '[{"id":"17976","text":"Si, porque son hormonas que se sintetizan en las neuronas hipotal&aacute;micas y se secretan hacia sistema porta adenohipofisiaria"},{"id":"17973","text":"No, porque son hormonas que se sintetizan en el hipot&aacute;lamo y pasan por flujo axonal desde el hipot&aacute;lamo a la adenohip&oacute;fisis"},{"id":"17974","text":"No, porque son hormonas que se sintetizan en la neurohip&oacute;fisis (l&oacute;bulo posterior de la hip&oacute;fisis)"},{"id":"17975","text":"Si, porque son hormonas que se sintetizan el hipot&aacute;lamo y se liberan acci&oacute;n sistema porta vascular hipot&aacute;lamo-neurohip&oacute;fisis"}]',
  '17976',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
