  'La hormona tiroidea:',
  75,
  '[{"id":"17978","text":"Tienen receptores intracelulares (nucleares) y la T3 (triyodotironina) es la forma m&aacute;s activa"},{"id":"17977","text":"Tiene receptores la membrana plasm&aacute;tica y la T3 (triyodotironina) es la que se encuentra en mayor concentraci&oacute;n de la sangre"},{"id":"17979","text":"Tienen receptores intracelulares, siendo la m&aacute;s activa la T4 debido a la sus mayores concentraciones plasm&aacute;ticas"},{"id":"17980","text":"Tienen receptores intracelulares y la forma m&aacute;s activa es la T4 (tiroxina)"}]',
  '17978',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
