INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x1-0000-4000-a000-000000006138',
  'a000161-0000-4000-a000-000000006136',
  'Respecto a la tensi&oacute;n superficial del agua en contacto con el aire:',
  1,
  '[{"id":"23681","text":"Las mol&eacute;culas superficiales est&aacute;n sometidas a fuerzas de adhesi&oacute;n (gas/agua) y la fuerza resultante genera la contracci&oacute;n de las mismas (sistema de alta energ&iacute;a)"},{"id":"23682","text":"Las mol&eacute;culas internas est&aacute;n sometidas a fuerzas de adhesi&oacute;n (agua/agua) y la fuerza resultante es cero (sistema de baja energ&iacute;a)"},{"id":"23683","text":"Las mol&eacute;culas superficiales est&aacute;n sometidas a fuerzas de cohesi&oacute;n (gas/agua) y la fuerza resultante es cero (sistema de baja energ&iacute;a)"},{"id":"23684","text":"Las mol&eacute;culas internas est&aacute;n sometidas a fuerzas de cohesi&oacute;n (agua/agua) y la fuerza resultante genera la contracci&oacute;n de las mismas (sistema de alta energ&iacute;a)"}]',
  '23681',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x2-0000-4000-a000-000000006139',
  'a000161-0000-4000-a000-000000006136',
  'Para que la funci&oacute;n pulmonar se lleve a cabo con &eacute;xito, debe existir un equilibrio entre las tensiones a la que los pulmones est&aacute;n sometidos. Se&ntilde;ale la respuesta correcta respecto a las caracter&iacute;sticas mec&aacute;nicas ventilatoria y las fuerzas que participan:',
  2,
  '[{"id":"23688","text":"Todas son correctas"},{"id":"23685","text":"La presi&oacute;n intrapleural participa en la distensi&oacute;n de los pulmones"},{"id":"23686","text":"La tensi&oacute;n superficial alveolar tiende a colapsar el pulm&oacute;n"},{"id":"23687","text":"La fuerza el&aacute;stica del pulm&oacute;n participa en la tendencia al colapso pulmonar"}]',
  '23688',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x3-0000-4000-a000-000000006140',
  'a000161-0000-4000-a000-000000006136',
  'Se&ntilde;ale la respuesta correcta respecto a las v&iacute;as respiratorias:',
  3,
  '[{"id":"23691","text":"La zona conducci&oacute;n es aquella donde no existen intercambio gaseoso y se corresponde con espacio muerto anat&oacute;mico"},{"id":"23689","text":"La zona de conducci&oacute;n es aquella donde se produce intercambio gaseoso y se corresponde con el espacio muerto fisiol&oacute;gico"},{"id":"23690","text":"La zona respiratoria es aquella donde se lleva a cabo el intercambio de gases y se corresponde con espacio muerto fisiol&oacute;gico"},{"id":"23692","text":"La zona respiratoria es aqu&eacute;lla donde no existe intercambio de gases y se corresponde con espacio muerto anat&oacute;mico"}]',
  '23691',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x4-0000-4000-a000-000000006141',
  'a000161-0000-4000-a000-000000006136',
  'Se&ntilde;ala la respuesta correcta:',
  4,
  '[{"id":"23693","text":"La inspiraci&oacute;n en la fase activa de la ventilaci&oacute;n pulmonar, se origina como consecuencia de la contracci&oacute;n muscular y el aire entra en los pulmones porque la presi&oacute;n intrapulmonar es menor que la atmosf&eacute;rica"},{"id":"23694","text":"La aspiraci&oacute;n es la fase activa de la ventilaci&oacute;n pulmonar, se origina como consecuencia de retorno el&aacute;stico del pulm&oacute;n y el aire sale de los pulmones porque la presi&oacute;n intrapulmonar es mayor que la atmosf&eacute;rica"},{"id":"23695","text":"La inspiraci&oacute;n es la fase pasiva de la ventilaci&oacute;n pulmonar, se origina como consecuencia de retorno el&aacute;stico del pulm&oacute;n y el aire entre los pulmones porque la presi&oacute;n intrapulmonar es mayor que la atmosf&eacute;rica"},{"id":"23696","text":"Respiraci&oacute;n la fase pasiva de la ventilaci&oacute;n pulmonar, se origina como consecuencia de la contracci&oacute;n muscular y el aire sale los pulmones porque la presi&oacute;n intrapulmonar es menor que la atmosf&eacute;rica"}]',
  '23693',
  '2026-04-17 15:42:45'
);
