INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x7-0000-4000-a000-000000006144',
  'a000161-0000-4000-a000-000000006136',
  '&iquest;C&oacute;mo soluciona el surfactante pulmonar el problema de la inestabilidad en el coeficiente V/Q debida a la diferencia de tama&ntilde;o en los alveolos pulmonares?',
  7,
  '[{"id":"23708","text":"Se produce en la misma cantidad en todos los alveolos, de manera que alveolos de mayor radio presenta menor tendencia al colapso que los peque&ntilde;os"},{"id":"23705","text":"Se produce en mayor cantidad en los alveolos de menor radio, de forma que la tendencia al colapso ser&aacute; menor"},{"id":"23706","text":"Se produce en la misma cantidad en todos los alveolos, de manera que alveolos de mayor radio presentan mayor tendencia al colapso que los peque&ntilde;os"},{"id":"23707","text":"Se produce en menor cantidad de los alveolos de mayor tama&ntilde;o, de forma que la tendencia al colapso sea mayor"}]',
