);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x8-0000-4000-a000-000000006145',
  'a000161-0000-4000-a000-000000006136',
  'Se&ntilde;ale la respuesta correcta respecto a la difusi&oacute;n y transporte de ox&iacute;geno en sangre:',
  8,
  '[{"id":"23712","text":"A y c son correctas"},{"id":"23709","text":"Muy poca cantidad va disuelta en plasma (<2%), en lo que se denomina como presi&oacute;n parcial de ox&iacute;geno y es la primera fracci&oacute;n de ox&iacute;geno que se entrega a los tejidos y que aumenta en sangre al pasar por el pulm&oacute;n"},{"id":"23710","text":"La mayor parte dar&aacute; disuelta en plasma (>98%), es lo que se denomina como presi&oacute;n parcial de oxigeno es la primera fracci&oacute;n que se entrega a los tejidos y que aumenta en sangre al pasar por pulm&oacute;n"},{"id":"23711","text":"La mayor parte va unido a la hemoglobina (>98%), es lo que se denomina como saturaci&oacute;n de ox&iacute;geno y es la &uacute;ltima fracci&oacute;n que se entrega a los tejidos y que aumentar&aacute; en sangre a pasar por el pulm&oacute;n"}]',
  '23712',
  '2026-04-17 15:42:45'
);
