  '23713',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x10-0000-4000-a000-000000006147',
  'a000161-0000-4000-a000-000000006136',
  '&iquest;Qu&eacute; significa que la curva de disociaci&oacute;n de la hemoglobina se desplace a la izquierda?',
  10,
  '[{"id":"23719","text":"Aumenta la afinidad de la hemoglobina por el ox&iacute;geno, es decir su P50 es menor que en condiciones fisiol&oacute;gicas"},{"id":"23717","text":"Disminuye la afinidad de la hemoglobina por el ox&iacute;geno, es decir su P50 es mayor que en condiciones fisiol&oacute;gicas"},{"id":"23718","text":"Aumenta la afinidad de la hemoglobina por el ox&iacute;geno, es decir su P50 es mayor que en condiciones fisiol&oacute;gicas"},{"id":"23720","text":"Disminuye la afinidad a la globina por el ox&iacute;geno, es decir su P50 es menor que en condiciones fisiol&oacute;gicas"}]',
  '23719',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x11-0000-4000-a000-000000006148',
  'a000161-0000-4000-a000-000000006136',
  '&iquest;En qu&eacute; consiste el efecto Bohr en los tejidos perif&eacute;ricos?',
  11,
  '[{"id":"23721","text":"Por diferencia de presiones entra CO2 en los eritrocitos, la disminuci&oacute;n de pH que genera este hecho hace que hemoglobina disminuye su afinidad por el ox&iacute;geno y lo libere hacia el tejido perif&eacute;rico"},{"id":"23722","text":"Por diferencia de presiones sale CO2 de los eritrocitos, el aumento de pH que generan este hecho hace que la hemoglobina disminuya su afinidad por el ox&iacute;geno y lo libere hacia el tejido perif&eacute;rico"},{"id":"23723","text":"Por diferencia de presiones entra CO2 de los eritrocitos, el aumento de pH que generan este hecho hace que la hemoglobina disminuya su afinidad por el ox&iacute;geno y lo libere hacia el tejido perif&eacute;rico"},{"id":"23724","text":"Por diferencia de presiones sale CO2 de los eritrocitos, la disminuci&oacute;n del pH que generan este hecho hace que la hemoglobina aumenta su afinidad por el ox&iacute;geno y lo libere hacia el tejido perif&eacute;rico"}]',
  '23721',
  '2026-04-17 15:42:45'
);
