INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x16-0000-4000-a000-000000006153',
  'a000161-0000-4000-a000-000000006136',
  'Se&ntilde;ale la respuesta correcta respecto a las v&iacute;as respiratorias:',
  16,
  '[{"id":"23744","text":"La zona respiratoria empieza en los bronquiolos respiratorios y acaba en los alv&eacute;olos, se caracteriza por la disminuci&oacute;n progresiva del calibre de sus v&iacute;as, aumentando de este modo la resistencia al paso de aire permitiendo el intercambio gaseoso"},{"id":"23741","text":"La zona de conducci&oacute;n empieza en las fosas nasales y acaba en los bronquiolos terminales, se caracteriza por la presencia de tejido cartilaginoso en todo su recorrido aumentando de este modo la resistencia al paso del aire"},{"id":"23742","text":"La zona de conducci&oacute;n empieza en los bronquiolos respiratorios y acaba en los bronquiolos terminales caracterizada por la presencia de alveolos respiratorios al final de su recorrido permitiendo de esta forma el intercambio gaseoso"},{"id":"23743","text":"La zona respiratoria empieza en los bronquiolos respiratorios y acaba en los alv&eacute;olos, se caracteriza por la presencia de tejido cartilaginoso en todo su recorrido aumentando de este modo la resistencia al paso de aire y permitiendo el intercambio gaseoso"}]',
  '23744',
  '2026-04-17 15:42:45'
);
