INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x20-0000-4000-a000-000000006157',
  'a000161-0000-4000-a000-000000006136',
  '&iquest;En qu&eacute; consiste el efecto Bohr?',
  20,
  '[{"id":"23757","text":"Por diferencia de presiones entra CO2 en los eritrocitos, la disminuci&oacute;n de pH que genera este hecho hace que la hemoglobina disminuya su afinidad por el O2 y lo libere hacia el tejido perif&eacute;rico"},{"id":"23758","text":"Por diferencia de presiones sale CO2 de los eritrocitos, el aumento de pH que genera este hecho hace que la hemoglobina disminuya su afinidad por el O2 y lo libere hacia el alveolo"},{"id":"23759","text":"Por diferencia de presiones entra CO2 en los eritrocitos, el aumento de pH que genera este hecho hace que la hemoglobina disminuya su afinidad por el O2 y lo libere hacia el tejido perif&eacute;rico"},{"id":"23760","text":"Por diferencia de presiones sale CO2 de los eritrocitos, la disminuci&oacute;n de pH que genera este hecho hace que la hemoglobina aumente su afinidad por el O2 y lo libere hacia el alveolo"}]',
  '23757',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
