  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x22-0000-4000-a000-000000006159',
  'a000161-0000-4000-a000-000000006136',
  'Los alv&eacute;olos de la parte dorsal del pulm&oacute;n entran dentro de lo que denominamos:',
  22,
  '[{"id":"23766","text":"Espacio muerto fisiol&oacute;gico, no se lleva a cabo el intercambio gaseoso al faltar perfusi&oacute;n por la propia disposici&oacute;n de los alv&eacute;olos"},{"id":"23765","text":"Espacio muerto anat&oacute;mico, no se lleva a cabo el intercambio gaseoso al faltar ventilaci&oacute;n por la propia disposici&oacute;n anat&oacute;mica de los alv&eacute;olos"},{"id":"23767","text":"Espacio muerto fisiol&oacute;gico, no se lleva a cabo el intercambio gaseoso al faltar ventilaci&oacute;n por la propia disposici&oacute;n anat&oacute;mica de los alv&eacute;olos"},{"id":"23768","text":"Espacio muerto anat&oacute;mico, no se lleva a cabo el intercambio gaseoso al faltar perfusi&oacute;n por la propia disposici&oacute;n anat&oacute;mica de los alv&eacute;olos"}]',
