INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x25-0000-4000-a000-000000006162',
  'a000161-0000-4000-a000-000000006136',
  'Se&ntilde;alen la respuesta correcta respeto a las v&iacute;as respiratorias:',
  25,
  '[{"id":"23779","text":"La zona de conducci&oacute;n es aquella donde no existe intercambio gaseoso y se corresponden con espacio muerto anat&oacute;mico"},{"id":"23777","text":"La zona de conducci&oacute;n es aquella donde se produce intercambio gaseoso y se corresponden con el espacio muerto fisiol&oacute;gico"},{"id":"23778","text":"La zona respiratoria es aquella donde se lleva a cabo el intercambio de gases y corresponden con el espacio muerto fisiol&oacute;gico"},{"id":"23780","text":"La zona respiratoria es aquella donde no existe de intercambio de gases y se corresponde con el espacio muerto anat&oacute;mico"}]',
  '23779',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x26-0000-4000-a000-000000006163',
  'a000161-0000-4000-a000-000000006136',
  'Se&ntilde;ale la respuesta correcta:',
  26,
  '[{"id":"23781","text":"La inspiraci&oacute;n es la fase activa de la ventilaci&oacute;n pulmonar, se origina como consecuencia de la contracci&oacute;n muscular y el aire que entra en los pulmones porque la presi&oacute;n intrapulmonar es menor que la atmosf&eacute;rica"},{"id":"23782","text":"La espiraci&oacute;n es la fase activa de la ventilaci&oacute;n pulmonar, se originan como consecuencia del retorno el&aacute;stico del pulm&oacute;n y el aire sale de los pulmones porque la presi&oacute;n intrapulmonar es mayor que la atmosf&eacute;rica"},{"id":"23783","text":"La inspiraci&oacute;n es la fase pasiva de la ventilaci&oacute;n pulmonar, se origina como consecuencia del retorno el&aacute;stico del pulm&oacute;n y el aire entra en los pulmones porque la presi&oacute;n intrapulmonar es mayor que la atmosf&eacute;rica"},{"id":"23784","text":"La espiraci&oacute;n es la fase pasiva de la ventilaci&oacute;n pulmonar, se origina como consecuencia de la contracci&oacute;n muscular y el aire sale de los pulmones porque la presi&oacute;n intrapulmonar es menor que la atmosf&eacute;rica"}]',
  '23781',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q161x27-0000-4000-a000-000000006164',
  'a000161-0000-4000-a000-000000006136',
