  27,
  '[{"id":"23788","text":"La presi&oacute;n de colapso en el alveolo es inversamente proporcional al radio del alveolo"},{"id":"23785","text":"La presi&oacute;n de colapso en el alveolo es directamente proporcional a la tensi&oacute;n superficial y al radio alveolar"},{"id":"23786","text":"La presi&oacute;n de colapso en el alveolo es inversamente proporcional a la tensi&oacute;n superficial y al radio alveolar"},{"id":"23787","text":"La presi&oacute;n del colapso en el alveolo es directamente proporcional al radio del alveolo"}]',
  '23788',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
