VALUES (
  'q164x40-0000-4000-a000-000000006327',
  'a000164-0000-4000-a000-000000006286',
  'Los bas&oacute;filos',
  40,
  '[{"id":"24428","text":"Son leucocitos poco abundantes en la sangre y su funci&oacute;n est&aacute; relacionada con la liberaci&oacute;n de sustancias que intervienen en la quimiotaxis y diap&eacute;desis"},{"id":"24425","text":"Son granulocitos poco abundantes y son muy activos como productos de opsoninas"},{"id":"24426","text":"Son agranulocitos poco abundantes en la sangre y act&uacute;an contra los par&aacute;sitos por la liberaci&oacute;n de sustancias toxicas"},{"id":"24427","text":"Son leucocitos poco abundantes en la sangre y act&uacute;an contra los par&aacute;sitos por la liberaci&oacute;n de sustancias toxicas"},{"id":"24429","text":"Son los &uacute;nicos gl&oacute;bulos blancos con capacidad de liberaci&oacute;n de sustancias vasoconstrictoras."}]',
