);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q164x41-0000-4000-a000-000000006328',
  'a000164-0000-4000-a000-000000006286',
  'Identifica la respuesta correcta',
  41,
  '[{"id":"24431","text":"Los monocitos son agranulocitos circulares y cuando est&aacute;n en los tejidos se denominan macr&oacute;fagos tisulares"},{"id":"24430","text":"Los neutr&oacute;filos son agranulocitos, que pueden salir de la sangre a trav&eacute;s de un mecanismo conocido como diap&eacute;desis"},{"id":"24432","text":"Los neutr&oacute;filos son granulocitos circulantes y no pueden actuar fuera de los vasos sangu&iacute;neos"},{"id":"24433","text":"Los macr&oacute;fagos tisulares son agranulocitos y se denominan de la misma forma tanto si est&aacute;n en los tejidos como si son circulantes."}]',
  '24431',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q164x42-0000-4000-a000-000000006329',
  'a000164-0000-4000-a000-000000006286',
  'Identifica la respuesta correcta:',
  42,
  '[{"id":"24436","text":"La formaci&oacute;n de carbaminohemoglobina supone una peque&ntilde;a parte del porcentaje de transporte de CO2, en la sangre."},{"id":"24434","text":"La formaci&oacute;n de carboxihemoglobina es la formaci&oacute;n habitual del transporte de CO2 en la sangre, siendo una uni&oacute;n laxa y reversible."},{"id":"24435","text":"La hemoglobina tiene muy poca afinidad por el CO (mon&oacute;xido de carbono) y su combinaci&oacute;n (carboxihemoglobina) es muy inestable"},{"id":"24437","text":"La formaci&oacute;n de oxihemoglobina es la forma habitual del transporte de O2 en la sangre, siendo una combinaci&oacute;n estable e irreversible."}]',
  '24436',
  '2026-04-17 15:42:45'
);
INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
