INSERT INTO QuizQuestion (id, assignmentId, questionText, questionOrder, options, correctOptionId, createdAt)
VALUES (
  'q199x2-0000-4000-a000-000000006505',
  'a000199-0000-4000-a000-000000006502',
  'Respecto a las variaciones que pueden aparecer en los caracteres de las poblaciones bacterianas. &iquest;Cu&aacute;l es correcta?',
  2,
  '[{"id":"26894","text":"Las variaciones del fenotipo por adaptaci&oacute;n al medio son heredables."},{"id":"26890","text":"Las modificaciones del fenotipo se deben siempre a conjugaci&oacute;n."},{"id":"26891","text":"Algunas bacterias producen toxinas en funci&oacute;n de que un nutriente (hierro) se encuentre en el medio."},{"id":"26892","text":"Las modificaciones del fenotipo se deben siempre a transformaci&oacute;n."},{"id":"26893","text":"Las mutaciones puntuales, microlesiones, nunca son silenciosas."}]',
  '26894',
  '2026-04-17 15:42:45'
);
