VALUES (
  'q199x4-0000-4000-a000-000000006507',
  'a000199-0000-4000-a000-000000006502',
  'En las modificaciones del ADN bacteriano:',
  4,
  '[{"id":"26904","text":"Todas las anteriores son ciertas."},{"id":"26900","text":"Una deleci&oacute;n es la completa eliminaci&oacute;n de un segmento de ADN."},{"id":"26901","text":"Una inversi&oacute;n es el cambio en la orientaci&oacute;n de un segmento de ADN"},{"id":"26902","text":"Una inserci&oacute;n es la introducci&oacute;n de un segmento de ADN dentro de una secuencia ya existente."},{"id":"26903","text":"Una translocaci&oacute;n es el desplazamiento de un segmento de ADN a otro sitio del genoma."}]',
