  'q199x5-0000-4000-a000-000000006508',
  'a000199-0000-4000-a000-000000006502',
  '&iquest;Cu&aacute;l de estas afirmaciones es verdadera?',
  5,
  '[{"id":"26905","text":"La replicaci&oacute;n del ADN de las bacterias es semiconservativa."},{"id":"26906","text":"La traducci&oacute;n tiene lugar en el n&uacute;cleo bacteriano."},{"id":"26907","text":"En la replicaci&oacute;n el ADN de la bacteria pasa a ARNm"},{"id":"26908","text":"El paso de ARNm a prote&iacute;na se llama transcripci&oacute;n."},{"id":"26909","text":"La enzima encargada de la transcripci&oacute;n es la ADN polimerasa."}]',
  '26905',
  '2026-04-17 15:42:45'
);
