  'q199x6-0000-4000-a000-000000006509',
  'a000199-0000-4000-a000-000000006502',
  'Una mutaci&oacute;n puntual...',
  6,
  '[{"id":"26912","text":"Puede ser de tipo transici&oacute;n o transversi&oacute;n."},{"id":"26910","text":"Siempre producir&aacute; una variaci&oacute;n fenot&iacute;pica."},{"id":"26911","text":"Afecta a varios pares de bases o incluso a varios genes."},{"id":"26913","text":"Siempre causa una mutaci&oacute;n sin sentido."},{"id":"26914","text":"Suele producir dimeros de pirimidinas."}]',
